CREATE OR REPLACE FUNCTION public.delete_world_with_quota(p_world_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_uid uuid;
  v_profile public.profiles%rowtype;
  v_world public.worlds%rowtype;
  v_total_bytes bigint;
  v_next_used_bytes bigint;
begin
  v_uid := auth.uid();

  if v_uid is null then
    raise exception 'not authenticated';
  end if;

  select *
  into v_profile
  from public.profiles
  where id = v_uid
  for update;

  if not found then
    raise exception 'profile not found';
  end if;

  select *
  into v_world
  from public.worlds
  where id = p_world_id
    and owner_id = v_uid
  for update;

  if not found then
    raise exception 'world not found or not owned';
  end if;

  v_total_bytes := coalesce(v_world.world_zip_bytes, 0) + coalesce(v_world.thumbnail_bytes, 0);
  v_next_used_bytes := greatest(0, v_profile.used_bytes - v_total_bytes);

  delete from public.worlds
  where id = v_world.id;

  update public.profiles
  set used_bytes = v_next_used_bytes
  where id = v_uid;

  insert into public.storage_usage_logs (
    owner_id,
    world_id,
    action,
    delta_bytes,
    used_bytes_after
  ) values (
    v_uid,
    p_world_id,
    'delete',
    -v_total_bytes,
    v_next_used_bytes
  );
end;
$function$

CREATE OR REPLACE FUNCTION public.increment_world_download_count(p_world_id uuid)
 RETURNS worlds
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_uid uuid;
  v_world public.worlds%rowtype;
begin
  v_uid := auth.uid();

  if v_uid is null then
    raise exception 'not authenticated';
  end if;

  select *
  into v_world
  from public.worlds
  where id = p_world_id
    and status = 'published'
  for update;

  if not found then
    raise exception 'world not found or not published';
  end if;

  insert into public.world_download_logs (
    world_id,
    user_id
  )
  values (
    p_world_id,
    v_uid
  )
  on conflict (world_id, user_id) do nothing;

  if found then
    update public.worlds
    set download_count = coalesce(download_count, 0) + 1
    where id = p_world_id
    returning *
    into v_world;
  end if;

  return v_world;
end;
$function$

CREATE OR REPLACE FUNCTION public.publish_world(p_world_id uuid)
 RETURNS worlds
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_uid uuid;
  v_world public.worlds%rowtype;
begin
  v_uid := auth.uid();

  if v_uid is null then
    raise exception 'not authenticated';
  end if;

  select *
  into v_world
  from public.worlds
  where id = p_world_id
    and owner_id = v_uid
  for update;

  if not found then
    raise exception 'world not found or not owned';
  end if;

  if coalesce(v_world.world_zip_path, '') = '' then
    raise exception 'world_zip_path is required';
  end if;

  update public.worlds
  set
    status = 'published',
    published_at = coalesce(published_at, now())
  where id = p_world_id
  returning *
  into v_world;

  return v_world;
end;
$function$

CREATE OR REPLACE FUNCTION public.reserve_asset_download(p_asset_id uuid)
 RETURNS TABLE(asset_id uuid, file_path text, file_size_bytes bigint, quota_group text, daily_limit_bytes bigint, used_bytes bigint, remaining_bytes bigint)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_uid uuid;
  v_asset public.downloadable_assets%rowtype;
  v_daily_limit_bytes bigint;
  v_used_bytes bigint;
  v_remaining_bytes bigint;
begin
  v_uid := auth.uid();
  if v_uid is null then
    raise exception 'not authenticated';
  end if;

  select *
  into v_asset
  from public.downloadable_assets
  where id = p_asset_id
    and status = 'published';

  if not found then
    raise exception 'asset not found or not published';
  end if;

  select dqp.daily_limit_bytes
  into v_daily_limit_bytes
  from public.download_quota_policies
  as dqp
  where dqp.quota_group = v_asset.quota_group;

  if v_daily_limit_bytes is null then
    raise exception 'quota policy not found';
  end if;

  insert into public.downloaded_bytes_log (user_id)
  values (v_uid)
  on conflict (user_id) do nothing;

  if v_asset.quota_group = 'structure_download' then
    select dbl.structure_downloaded_bytes
    into v_used_bytes
    from public.downloaded_bytes_log as dbl
    where dbl.user_id = v_uid
    for update;
  else
    select dbl.asset_downloaded_bytes
    into v_used_bytes
    from public.downloaded_bytes_log as dbl
    where dbl.user_id = v_uid
    for update;
  end if;

  v_used_bytes := coalesce(v_used_bytes, 0);

  if v_used_bytes + v_asset.file_size_bytes > v_daily_limit_bytes then
    raise exception 'daily download quota exceeded';
  end if;

  if v_asset.quota_group = 'structure_download' then
    update public.downloaded_bytes_log
    set structure_downloaded_bytes = structure_downloaded_bytes + v_asset.file_size_bytes
    where user_id = v_uid;
  else
    update public.downloaded_bytes_log
    set asset_downloaded_bytes = asset_downloaded_bytes + v_asset.file_size_bytes
    where user_id = v_uid;
  end if;

  v_used_bytes := v_used_bytes + v_asset.file_size_bytes;
  v_remaining_bytes := greatest(0, v_daily_limit_bytes - v_used_bytes);

  return query
  select
    v_asset.id,
    v_asset.file_path,
    v_asset.file_size_bytes,
    v_asset.quota_group,
    v_daily_limit_bytes,
    v_used_bytes,
    v_remaining_bytes;
end;
$function$

CREATE OR REPLACE FUNCTION public.reserve_world_download(p_world_id uuid, p_usage_type text DEFAULT 'download'::text)
 RETURNS TABLE(world_id uuid, world_zip_path text, world_zip_bytes bigint, charged_bytes bigint, daily_limit_bytes bigint, used_bytes bigint, remaining_bytes bigint)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_uid uuid;
  v_world public.worlds%rowtype;
  v_daily_limit_bytes bigint;
  v_used_bytes bigint;
  v_remaining_bytes bigint;
  v_charged_bytes bigint;
begin
  v_uid := auth.uid();
  if v_uid is null then
    raise exception 'not authenticated';
  end if;

  if coalesce(trim(p_usage_type), '') not in ('download', 'resume', 'thumbnail_resume') then
    raise exception 'invalid usage type';
  end if;

  select w.*
  into v_world
  from public.worlds as w
  where w.id = p_world_id
    and (
      (p_usage_type = 'download' and w.status = 'published')
      or
      (p_usage_type in ('resume', 'thumbnail_resume') and w.owner_id = v_uid)
    );

  if not found then
    raise exception 'world not found or unavailable';
  end if;

  select dqp.daily_limit_bytes
  into v_daily_limit_bytes
  from public.download_quota_policies as dqp
  where dqp.quota_group = 'structure_download';

  if v_daily_limit_bytes is null then
    raise exception 'quota policy not found';
  end if;

  insert into public.downloaded_bytes_log (user_id)
  values (v_uid)
  on conflict (user_id) do nothing;

  select dbl.structure_downloaded_bytes
  into v_used_bytes
  from public.downloaded_bytes_log as dbl
  where dbl.user_id = v_uid
  for update;

  v_used_bytes := coalesce(v_used_bytes, 0);
  v_charged_bytes := case
    when p_usage_type = 'download' then coalesce(v_world.world_zip_bytes, 0)
    else greatest(1, ceil(coalesce(v_world.world_zip_bytes, 0)::numeric * 0.5)::bigint)
  end;

  if v_used_bytes + v_charged_bytes > v_daily_limit_bytes then
    raise exception 'structure download quota exceeded';
  end if;

  update public.downloaded_bytes_log
  set structure_downloaded_bytes = structure_downloaded_bytes + v_charged_bytes
  where user_id = v_uid;

  v_used_bytes := v_used_bytes + v_charged_bytes;
  v_remaining_bytes := greatest(0, v_daily_limit_bytes - v_used_bytes);

  return query
  select
    v_world.id,
    v_world.world_zip_path,
    coalesce(v_world.world_zip_bytes, 0),
    v_charged_bytes,
    v_daily_limit_bytes,
    v_used_bytes,
    v_remaining_bytes;
end;
$function$

CREATE OR REPLACE FUNCTION public.reserve_world_download(p_world_id uuid)
 RETURNS TABLE(world_id uuid, world_zip_path text, world_zip_bytes bigint, daily_limit_bytes bigint, used_bytes bigint, remaining_bytes bigint)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_uid uuid;
  v_world public.worlds%rowtype;
  v_daily_limit_bytes bigint;
  v_used_bytes bigint;
  v_remaining_bytes bigint;
begin
  v_uid := auth.uid();
  if v_uid is null then
    raise exception 'not authenticated';
  end if;

  select w.*
  into v_world
  from public.worlds as w
  where w.id = p_world_id
    and w.status = 'published';

  if not found then
    raise exception 'world not found or not published';
  end if;

  select dqp.daily_limit_bytes
  into v_daily_limit_bytes
  from public.download_quota_policies as dqp
  where dqp.quota_group = 'structure_download';

  if v_daily_limit_bytes is null then
    raise exception 'quota policy not found';
  end if;

  insert into public.downloaded_bytes_log (user_id)
  values (v_uid)
  on conflict (user_id) do nothing;

  select dbl.structure_downloaded_bytes
  into v_used_bytes
  from public.downloaded_bytes_log as dbl
  where dbl.user_id = v_uid
  for update;

  v_used_bytes := coalesce(v_used_bytes, 0);

  if v_used_bytes + coalesce(v_world.world_zip_bytes, 0) > v_daily_limit_bytes then
    raise exception 'structure download quota exceeded';
  end if;

  update public.downloaded_bytes_log
  set structure_downloaded_bytes = structure_downloaded_bytes + coalesce(v_world.world_zip_bytes, 0)
  where user_id = v_uid;

  v_used_bytes := v_used_bytes + coalesce(v_world.world_zip_bytes, 0);
  v_remaining_bytes := greatest(0, v_daily_limit_bytes - v_used_bytes);

  return query
  select
    v_world.id,
    v_world.world_zip_path,
    coalesce(v_world.world_zip_bytes, 0),
    v_daily_limit_bytes,
    v_used_bytes,
    v_remaining_bytes;
end;
$function$

CREATE OR REPLACE FUNCTION public.resolve_world_zip_size(p_world_zip_path text)
 RETURNS bigint
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_size bigint;
begin
  if coalesce(trim(p_world_zip_path), '') = '' then
    raise exception 'world_zip_path is required';
  end if;

  select coalesce((so.metadata->>'size')::bigint, 0)
  into v_size
  from storage.objects as so
  where so.bucket_id = 'world-files'
    and so.name = p_world_zip_path;

  if v_size is null then
    raise exception 'world zip object not found';
  end if;

  if v_size < 0 then
    raise exception 'invalid world zip size';
  end if;

  return v_size;
end;
$function$

