CREATE OR REPLACE FUNCTION public.unpublish_world(p_world_id uuid)
 RETURNS worlds
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_uid uuid;
