CREATE OR REPLACE FUNCTION public.update_world_metadata(p_world_id uuid, p_title text, p_description text, p_status text, p_thumbnail_path text, p_thumbnail_bytes bigint, p_origin_id text, p_slot integer)
 RETURNS worlds
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_uid uuid;
  v_world public.worlds%rowtype;
begin
  v_uid := auth.uid();

  if v_uid is null then
    raise exception 'not authenticated';
