CREATE OR REPLACE FUNCTION public.update_world_with_quota(p_world_id uuid, p_title text, p_description text, p_status text, p_world_zip_path text, p_world_zip_bytes bigint, p_thumbnail_path text, p_thumbnail_bytes bigint)
 RETURNS worlds
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_uid uuid;
  v_profile public.profiles%rowtype;
  v_world public.worlds%rowtype;
  v_old_total bigint;
  v_new_total bigint;
  v_delta bigint;
  v_next_used_bytes bigint;
begin
  v_uid := auth.uid();

  if v_uid is null then
    raise exception 'not authenticated';
  end if;

  if p_status not in ('draft', 'published', 'archived') then
    raise exception 'invalid status';
  end if;

  if coalesce(p_world_zip_bytes, 0) < 0 then
    raise exception 'invalid world_zip_bytes';
  end if;

  if coalesce(p_thumbnail_bytes, 0) < 0 then
    raise exception 'invalid thumbnail_bytes';
  end if;

  if coalesce(p_thumbnail_bytes, 0) > 5120 then
    raise exception 'thumbnail exceeds 5KB limit';
  end if;

  select *
  into v_profile
  from public.profiles
  where id = v_uid
  for update;

  if not found then
    raise exception 'profile not found';
  end if;

  select *
  into v_world
  from public.worlds
  where id = p_world_id
    and owner_id = v_uid
  for update;

  if not found then
    raise exception 'world not found or not owned';
  end if;

  v_old_total := coalesce(v_world.world_zip_bytes, 0) + coalesce(v_world.thumbnail_bytes, 0);
  v_new_total := coalesce(p_world_zip_bytes, 0) + coalesce(p_thumbnail_bytes, 0);
  v_delta := v_new_total - v_old_total;
  v_next_used_bytes := v_profile.used_bytes + v_delta;

  if v_next_used_bytes > v_profile.quota_bytes then
    raise exception 'quota exceeded';
  end if;

  update public.worlds
  set
    title = p_title,
    description = p_description,
    status = p_status,
    world_zip_path = p_world_zip_path,
    world_zip_bytes = coalesce(p_world_zip_bytes, 0),
    thumbnail_path = p_thumbnail_path,
    thumbnail_bytes = coalesce(p_thumbnail_bytes, 0)
  where id = p_world_id
  returning *
  into v_world;

  update public.profiles
  set used_bytes = greatest(0, v_next_used_bytes)
  where id = v_uid;

  insert into public.storage_usage_logs (
    owner_id,
    world_id,
    action,
    delta_bytes,
    used_bytes_after
  ) values (
    v_uid,
    p_world_id,
    'update',
    v_delta,
    greatest(0, v_next_used_bytes)
  );

  return v_world;
end;
